mapper.select:
/* PRVYY_SAMM_VERSUS_CNSMP_STTUS_Dao_retrievePrvyySammVersusCnsmpSttusList */
, MONTH_LIST AS ( SELECT /*+ MATERIALZE */ SUBSTR(#{strtDt}, 0, 6) AS mt FROM DUAL UNION ALL SELECT SUBSTR(#{endDt}, 0, 6) AS mt FROM DUAL ) SELECT
ROWNUM AS "no", dscfc_lclhq_cd AS basin_cd, dscfc_lclhq_nm AS basin_nm, dscfc_bplc_cd AS dept_cd, dscfc_bplc_nm AS dept_nm, prvyy_pwcsp, thsyy_pwcsp, irds_qy, redcn_rt FROM ( SELECT dscfc_lclhq_cd, dscfc_lclhq_nm, dscfc_bplc_cd, dscfc_bplc_nm, ROUND(prvyy_pwcsp, 0) AS prvyy_pwcsp, ROUND(thsyy_pwcsp, 0) AS thsyy_pwcsp, ROUND(irds_qy, 0) AS irds_qy, CASE WHEN thsyy_pwcsp > 0 AND prvyy_pwcsp > 0 THEN ROUND(irds_qy / prvyy_pwcsp * 100, 1) ELSE 0 END AS redcn_rt FROM ( SELECT /*+ LEADING(MAPPING_LIST PRVYY THSYY) */ MAX(MAPPING_LIST.dscfc_lclhq_cd) AS dscfc_lclhq_cd, MAX(MAPPING_LIST.dscfc_lclhq_nm) AS dscfc_lclhq_nm, MAPPING_LIST.dscfc_bplc_cd, MAX(MAPPING_LIST.dscfc_bplc_nm) AS dscfc_bplc_nm, NVL(SUM(PRVYY.dscfc_usgqty), 0) AS prvyy_pwcsp, NVL(SUM(THSYY.dscfc_usgqty), 0) AS thsyy_pwcsp, NVL(SUM(THSYY.dscfc_usgqty), 0) - NVL(SUM(PRVYY.dscfc_usgqty), 0) AS irds_qy FROM ( SELECT MONTH_LIST.mt, A.dscfc_lclhq_cd, A.dscfc_lclhq_nm, A.dscfc_bplc_cd, A.dscfc_bplc_nm, A.dscfc_id FROM ( SELECT MAX(dscfc_lclhq_cd) AS dscfc_lclhq_cd, MAX(dscfc_lclhq_nm) AS dscfc_lclhq_nm, MAX(dscfc_bplc_cd) AS dscfc_bplc_cd, MAX(dscfc_bplc_nm) AS dscfc_bplc_nm, dscfc_id FROM GHG_DATA_LIST GROUP BY dscfc_id ) A, MONTH_LIST ) MAPPING_LIST, ( SELECT SUBSTR(dscfc_use_de, 0, 6) AS dscfc_use_de, dscfc_id, SUM(dscfc_usgqty) AS dscfc_usgqty FROM GHG_DATA_LIST WHERE dscfc_use_de BETWEEN ( SELECT MIN(mt) FROM MONTH_LIST ) || '01' AND ( SELECT MIN(mt) FROM MONTH_LIST ) || '31' GROUP BY SUBSTR(dscfc_use_de, 0, 6), dscfc_id ) PRVYY, ( SELECT SUBSTR(dscfc_use_de, 0, 6) AS dscfc_use_de, dscfc_id, SUM(dscfc_usgqty) AS dscfc_usgqty FROM GHG_DATA_LIST WHERE dscfc_use_de BETWEEN ( SELECT MAX(mt) FROM MONTH_LIST ) || '01' AND ( SELECT MAX(mt) FROM MONTH_LIST ) || '31' GROUP BY SUBSTR(dscfc_use_de, 0, 6), dscfc_id ) THSYY WHERE MAPPING_LIST.dscfc_id = PRVYY.dscfc_id(+) AND MAPPING_LIST.mt = PRVYY.dscfc_use_de(+) AND MAPPING_LIST.dscfc_id = THSYY.dscfc_id(+) AND MAPPING_LIST.mt = THSYY.dscfc_use_de(+) GROUP BY MAPPING_LIST.dscfc_bplc_cd ) ORDER BY redcn_rt DESC, irds_qy DESC ) ORDER BY "no"

/* PRVYY_SAMM_VERSUS_CNSMP_STTUS_Dao_retrievePrvyySammVersusCnsmpSttusChartList */
, MONTH_LIST AS ( SELECT /*+ MATERIALZE */ SUBSTR(#{strtDt}, 0, 6) AS mt FROM DUAL UNION ALL SELECT SUBSTR(#{endDt}, 0, 6) AS mt FROM DUAL ) SELECT dscfc_procs_ty_cd, dscfc_procs_ty_nm, ROUND(prvyy_pwcsp, 0) AS prvyy_pwcsp, ROUND(thsyy_pwcsp, 0) AS thsyy_pwcsp, ROUND(irds_qy, 0) AS irds_qy, CASE WHEN thsyy_pwcsp > 0 AND prvyy_pwcsp > 0 THEN ROUND(irds_qy / prvyy_pwcsp * 100, 1) ELSE 0 END AS redcn_rt FROM ( SELECT /*+ LEADING(MAPPING_LIST PRVYY THSYY) */ MAPPING_LIST.dscfc_procs_ty_cd, MAX(MAPPING_LIST.dscfc_procs_ty_nm) AS dscfc_procs_ty_nm, NVL(SUM(PRVYY.dscfc_usgqty), 0) AS prvyy_pwcsp, NVL(SUM(THSYY.dscfc_usgqty), 0) AS thsyy_pwcsp, NVL(SUM(THSYY.dscfc_usgqty), 0) - NVL(SUM(PRVYY.dscfc_usgqty), 0) AS irds_qy FROM ( SELECT MONTH_LIST.mt, A.dscfc_lclhq_cd, A.dscfc_lclhq_nm, A.dscfc_bplc_cd, A.dscfc_bplc_nm, A.dscfc_procs_ty_cd, A.dscfc_procs_ty_nm, A.dscfc_id FROM ( SELECT MAX(dscfc_lclhq_cd) AS dscfc_lclhq_cd, MAX(dscfc_lclhq_nm) AS dscfc_lclhq_nm, MAX(dscfc_bplc_cd) AS dscfc_bplc_cd, MAX(dscfc_bplc_nm) AS dscfc_bplc_nm, MAX(dscfc_procs_ty_cd) AS dscfc_procs_ty_cd, MAX(dscfc_procs_ty_nm) AS dscfc_procs_ty_nm, dscfc_id FROM GHG_DATA_LIST GROUP BY dscfc_id ) A, MONTH_LIST ) MAPPING_LIST, ( SELECT SUBSTR(dscfc_use_de, 0, 6) AS dscfc_use_de, dscfc_id, SUM(dscfc_usgqty) AS dscfc_usgqty FROM GHG_DATA_LIST WHERE dscfc_use_de BETWEEN ( SELECT MIN(mt) FROM MONTH_LIST ) || '01' AND ( SELECT MIN(mt) FROM MONTH_LIST ) || '31' GROUP BY SUBSTR(dscfc_use_de, 0, 6), dscfc_id ) PRVYY, ( SELECT SUBSTR(dscfc_use_de, 0, 6) AS dscfc_use_de, dscfc_id, SUM(dscfc_usgqty) AS dscfc_usgqty FROM GHG_DATA_LIST WHERE dscfc_use_de BETWEEN ( SELECT MAX(mt) FROM MONTH_LIST ) || '01' AND ( SELECT MAX(mt) FROM MONTH_LIST ) || '31' GROUP BY SUBSTR(dscfc_use_de, 0, 6), dscfc_id ) THSYY WHERE MAPPING_LIST.dscfc_id = PRVYY.dscfc_id(+) AND MAPPING_LIST.mt = PRVYY.dscfc_use_de(+) AND MAPPING_LIST.dscfc_id = THSYY.dscfc_id(+) AND MAPPING_LIST.mt = THSYY.dscfc_use_de(+)
AND MAPPING_LIST.dscfc_bplc_cd = #{ecsChrgDeptId}
GROUP BY MAPPING_LIST.dscfc_procs_ty_cd ) ORDER BY redcn_rt DESC, irds_qy DESC
